SELECT 4 AS [Source Type], Item.[Model Item No_] AS [Source No_], 0 AS [Source Line No_], 10000 AS [Line No_], 2 AS [Document Type], "_" AS Description, "X:\febos\foto\" & [marchiocartella] & "\" & [season code] & "\Foto Navision\" & [nome effettivo (incolla valori)] AS [Linked Document], 0 AS Priority, 0 AS [File Not Found], "_" AS [Picture CapTion], Item.[Constant Assortment Var_Grp_], Item.[Variable Code 01] AS [Constant Variable CodE]
FROM (Item LEFT JOIN RelazioniMarchiCartelle ON Item.[Trademark Code] = RelazioniMarchiCartelle.Marchio) INNER JOIN [LINELIST FW24 CPH] ON (Item.[Variable Code 01] = [LINELIST FW24 CPH].[COLOR CODE]) AND (Item.[Model Item No_] = [LINELIST FW24 CPH].[STYLE CODE])
GROUP BY 4, Item.[Model Item No_], 10000, 2, "X:\febos\foto\" & [marchiocartella] & "\" & [season code] & "\Foto Navision\" & [nome effettivo (incolla valori)], 0, "_", Item.[Constant Assortment Var_Grp_], Item.[Variable Code 01], 0, Item.[Configurator Relation], Item.[Trademark Code], Item.[Season Code], 0, 0, ""
HAVING (((Item.[Configurator Relation])=[Configurator relation Filter]) AND ((Item.[Trademark Code])=[forms]![principale]![filtromarchiopergeneralinks]) AND ((Item.[Season Code])=[forms]![principale]![filtrostagionepergeneralinks]));

